  1	import {
  2	  consoleFetchJSON,
  3	  GreenCheckCircleIcon,
  4	  Silence,
  5	  SilenceStates,
  6	  useActiveNamespace,
  7	} from '@openshift-console/dynamic-plugin-sdk';
  8	import {
  9	  Button,
 10	  Checkbox,
 11	  Dropdown,
 12	  DropdownItem,
 13	  DropdownList,
 14	  Flex,
 15	  FlexItem,
 16	  Label,
 17	  MenuToggle,
 18	  MenuToggleElement,
 19	  Modal,
 20	  ModalVariant,
 21	  Panel,
 22	  PanelMain,
 23	  PanelMainBody,
 24	  Alert as PFAlert,
 25	} from '@patternfly/react-core';
 26	import { BanIcon, EllipsisVIcon, HourglassHalfIcon } from '@patternfly/react-icons';
 27	import classNames from 'classnames';
 28	import * as _ from 'lodash-es';
 29	import * as React from 'react';
 30	import { useTranslation } from 'react-i18next';
 31	import { useDispatch } from 'react-redux';
 32	import { Link, RouteComponentProps, withRouter } from 'react-router-dom';
 33	import { useBoolean } from '../hooks/useBoolean';
 34	import {
 35	  getEditSilenceAlertUrl,
 36	  getFetchSilenceUrl,
 37	  getSilenceAlertUrl,
 38	  usePerspective,
 39	} from '../hooks/usePerspective';
 40	import {
 41	  refreshSilences,
 42	  silenceMatcherEqualitySymbol,
 43	  SilenceResource,
 44	  silenceState,
 45	} from '../utils';
 46	import { MonitoringResourceIcon, SeverityCounts, StateTimestamp } from './AlertUtils';
 47	import { LoadingInline } from '../console/console-shared/src/components/loading/LoadingInline';
 48	import { Td } from '@patternfly/react-table';
 49	
 50	export const tableSilenceClasses = [
 51	  'pf-v6-c-table__action', // Checkbox
 52	  'pf-u-w-50 pf-u-w-33-on-sm', // Name
 53	  'pf-m-hidden pf-m-visible-on-sm', // Firing alerts
 54	  '', // State
 55	  'pf-m-hidden pf-m-visible-on-sm', // Creator
 56	  'pf-m-hidden pf-m-visible-on-sm', // Cluster
 57	  'dropdown-kebab-pf pf-v6-c-table__action',
 58	];
 59	
 60	export const SilenceTableRow: React.FC<SilenceTableRowProps> = ({ obj, showCheckbox }) => {
 61	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
 62	  const { perspective } = usePerspective();
 63	  const [namespace] = useActiveNamespace();
 64	
 65	  const { createdBy, endsAt, firingAlerts, id, name, startsAt, matchers } = obj;
 66	  const state = silenceState(obj);
 67	  const cluster = matchers.find((label) => label.name === 'cluster')?.value;
 68	
 69	  const { selectedSilences, setSelectedSilences } = React.useContext(SelectedSilencesContext);
 70	
 71	  const onCheckboxChange = React.useCallback(
 72	    (isChecked: boolean) => {
 73	      setSelectedSilences((oldSet) => {
 74	        const newSet = new Set(oldSet);
 75	        if (isChecked) {
 76	          newSet.add(id);
 77	        } else {
 78	          newSet.delete(id);
 79	        }
 80	        return newSet;
 81	      });
 82	    },
 83	    [id, setSelectedSilences],
 84	  );
 85	
 86	  return (
 87	    <>
 88	      {showCheckbox && (
 89	        <Td className={tableSilenceClasses[0]}>
 90	          <Checkbox
 91	            id={id}
 92	            isChecked={selectedSilences.has(id)}
 93	            isDisabled={state === SilenceStates.Expired}
 94	            onChange={(_e, checked) => {
 95	              typeof _e === 'boolean' ? onCheckboxChange(checked) : onCheckboxChange(checked);
 96	            }}
 97	          />
 98	        </Td>
 99	      )}
100	      <Td className={tableSilenceClasses[1]}>
101	        <Flex spaceItems={{ default: 'spaceItemsNone' }} flexWrap={{ default: 'nowrap' }}>
102	          <FlexItem>
103	            <MonitoringResourceIcon resource={SilenceResource} />
104	          </FlexItem>
105	          <FlexItem>
106	            <Link
107	              data-test-id="silence-resource-link"
108	              title={id}
109	              to={getSilenceAlertUrl(perspective, id, namespace)}
110	            >
111	              {name}
112	            </Link>
113	          </FlexItem>
114	        </Flex>
115	        <div className="monitoring-label-list">
116	          <SilenceMatchersList silence={obj} />
117	        </div>
118	      </Td>
119	      <Td className={tableSilenceClasses[2]}>
120	        <SeverityCounts alerts={firingAlerts} />
121	      </Td>
122	      <Td className={classNames(tableSilenceClasses[3], 'pf-v6-u-text-break-word')}>
123	        <SilenceState silence={obj} />
124	        {state === SilenceStates.Pending && (
125	          <StateTimestamp text={t('Starts')} timestamp={startsAt} />
126	        )}
127	        {state === SilenceStates.Active && <StateTimestamp text={t('Ends')} timestamp={endsAt} />}
128	        {state === SilenceStates.Expired && (
129	          <StateTimestamp text={t('Expired')} timestamp={endsAt} />
130	        )}
131	      </Td>
132	      <Td className={tableSilenceClasses[4]}>{createdBy || '-'}</Td>
133	      {perspective === 'acm' && <Td className={tableSilenceClasses[5]}>{cluster}</Td>}
134	      <Td className={tableSilenceClasses[6]}>
135	        <SilenceDropdown silence={obj} />
136	      </Td>
137	    </>
138	  );
139	};
140	
141	type SilenceTableRowProps = {
142	  obj: Silence;
143	  showCheckbox?: boolean;
144	};
145	
146	export const SelectedSilencesContext = React.createContext({
147	  selectedSilences: new Set(),
148	  setSelectedSilences: undefined,
149	});
150	
151	export const SilenceMatchersList = ({ silence }) => (
152	  <div>
153	    {_.map(silence.matchers, ({ name, isEqual, isRegex, value }, i) => (
154	      <Label key={i}>
155	        <span>{name}</span>
156	        <span>{silenceMatcherEqualitySymbol(isEqual, isRegex)}</span>
157	        <span>{value}</span>
158	      </Label>
159	    ))}
160	  </div>
161	);
162	
163	export type ExpireSilenceModalProps = {
164	  isOpen: boolean;
165	  setClosed: () => void;
166	  silenceID: string;
167	};
168	
169	export const SilenceState = ({ silence }) => {
170	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
171	
172	  const state = silenceState(silence);
173	  const icon = {
174	    [SilenceStates.Active]: <GreenCheckCircleIcon />,
175	    [SilenceStates.Pending]: <HourglassHalfIcon className="monitoring-state-icon--pending" />,
176	    [SilenceStates.Expired]: <BanIcon className="text-muted" data-test-id="ban-icon" />,
177	  }[state];
178	
179	  const getStateKey = (stateData) => {
180	    switch (stateData) {
181	      case SilenceStates.Active:
182	        return t('Active');
183	      case SilenceStates.Pending:
184	        return t('Pending');
185	      default:
186	        return t('Expired');
187	    }
188	  };
189	
190	  return icon ? (
191	    <>
192	      {icon} {getStateKey(state)}
193	    </>
194	  ) : null;
195	};
196	
197	const SilenceDropdown_: React.FC<SilenceDropdownProps> = ({ history, silence, toggleText }) => {
198	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
199	  const { perspective } = usePerspective();
200	  const [namespace] = useActiveNamespace();
201	
202	  const [isOpen, setIsOpen, , setClosed] = useBoolean(false);
203	  const [isModalOpen, , setModalOpen, setModalClosed] = useBoolean(false);
204	
205	  const editSilence = () => {
206	    history.push(getEditSilenceAlertUrl(perspective, silence.id, namespace));
207	  };
208	
209	  const dropdownItems =
210	    silenceState(silence) === SilenceStates.Expired
211	      ? [
212	          <DropdownItem value={0} key="recreate-silence" onClick={editSilence}>
213	            {t('Recreate silence')}
214	          </DropdownItem>,
215	        ]
216	      : [
217	          <DropdownItem value={0} key="edit-silence" onClick={editSilence}>
218	            {t('Edit silence')}
219	          </DropdownItem>,
220	          <DropdownItem value={1} key="cancel-silence" onClick={setModalOpen}>
221	            {t('Expire silence')}
222	          </DropdownItem>,
223	        ];
224	
225	  return (
226	    <>
227	      <Dropdown
228	        isOpen={isOpen}
229	        onSelect={setClosed}
230	        data-test="silence-actions"
231	        popperProps={{ position: 'right' }}
232	        onOpenChange={(isOpen: boolean) => (isOpen ? setIsOpen() : setClosed())}
233	        toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
234	          <MenuToggle
235	            ref={toggleRef}
236	            aria-label="kebab dropdown toggle"
237	            variant={toggleText ? 'default' : 'plain'}
238	            onClick={setIsOpen}
239	            isExpanded={isOpen}
240	          >
241	            {toggleText || <EllipsisVIcon />}
242	          </MenuToggle>
243	        )}
244	      >
245	        <DropdownList>{dropdownItems}</DropdownList>
246	      </Dropdown>
247	      <ExpireSilenceModal isOpen={isModalOpen} setClosed={setModalClosed} silenceID={silence.id} />
248	    </>
249	  );
250	};
251	export const SilenceDropdown = withRouter(SilenceDropdown_);
252	
253	const ExpireSilenceModal: React.FC<ExpireSilenceModalProps> = ({
254	  isOpen,
255	  setClosed,
256	  silenceID,
257	}) => {
258	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
259	  const { perspective, silencesKey } = usePerspective();
260	  const [namespace] = useActiveNamespace();
261	
262	  const dispatch = useDispatch();
263	
264	  const [isInProgress, , setInProgress, setNotInProgress] = useBoolean(false);
265	  const [errorMessage, setErrorMessage] = React.useState();
266	
267	  const expireSilence = () => {
268	    setInProgress();
269	    const url = getFetchSilenceUrl(perspective, silenceID, namespace);
270	    consoleFetchJSON
271	      .delete(url)
272	      .then(() => {
273	        refreshSilences(dispatch, perspective, silencesKey);
274	        setClosed();
275	      })
276	      .catch((err) => {
277	        setErrorMessage(_.get(err, 'json.error') || err.message || 'Error expiring silence');
278	        setNotInProgress();
279	      })
280	      .then(setNotInProgress);
281	  };
282	
283	  return (
284	    <Modal
285	      isOpen={isOpen}
286	      position="top"
287	      showClose={false}
288	      title={t('Expire silence')}
289	      variant={ModalVariant.small}
290	    >
291	      <Flex direction={{ default: 'column' }}>
292	        <FlexItem>{t('Are you sure you want to expire this silence?')}</FlexItem>
293	        <Flex direction={{ default: 'column' }}>
294	          <FlexItem>
295	            {errorMessage && (
296	              <PFAlert isInline title={t('An error occurred')} variant="danger">
297	                <Panel isScrollable>
298	                  <PanelMain maxHeight="100px">
299	                    <PanelMainBody className="pf-v6-u-text-break-word monitoring__pre-line">
300	                      {errorMessage}
301	                    </PanelMainBody>
302	                  </PanelMain>
303	                </Panel>
304	              </PFAlert>
305	            )}
306	          </FlexItem>
307	          <Flex>
308	            <FlexItem>{isInProgress && <LoadingInline />}</FlexItem>
309	            <FlexItem align={{ default: 'alignRight' }}>
310	              <Button variant="secondary" onClick={setClosed}>
311	                {t('Cancel')}
312	              </Button>
313	            </FlexItem>
314	            <FlexItem>
315	              <Button variant="primary" onClick={expireSilence}>
316	                {t('Expire silence')}
317	              </Button>
318	            </FlexItem>
319	          </Flex>
320	        </Flex>
321	      </Flex>
322	    </Modal>
323	  );
324	};
325	
326	type SilenceDropdownProps = RouteComponentProps & {
327	  silence: Silence;
328	  toggleText?: string;
329	};

