266	  const [isInProgress, , setInProgress, setNotInProgress] = useBoolean(false);
267	  const [errorMessage, setErrorMessage] = React.useState();
268	
269	  const expireSilence = () => {
270	    setInProgress();
271	    const url = getFetchSilenceUrl(perspective, silenceID, namespace);
272	    consoleFetchJSON
273	      .delete(url)
274	      .then(() => {
275	        refreshSilences(dispatch, perspective, silencesKey);
276	        setClosed();
277	      })
278	      .catch((err) => {
279	        setErrorMessage(_.get(err, 'json.error') || err.message || 'Error expiring silence');
280	        setNotInProgress();
281	      })
282	      .then(setNotInProgress);
283	  };
284	
285	  return (
286	    <Modal
287	      isOpen={isOpen}
288	      position="top"
289	      variant={ModalVariant.small}
290	    >
291	      <ModalHeader title={t('Expire silence')} />
292	      <ModalBody>
293	        <Flex direction={{ default: 'column' }}>
294	          <FlexItem>{t('Are you sure you want to expire this silence?')}</FlexItem>
295	          <Flex direction={{ default: 'column' }}>
296	            <FlexItem>
297	              {errorMessage && (
298	                <PFAlert isInline title={t('An error occurred')} variant="danger">
299	                  <Panel isScrollable>
300	                    <PanelMain maxHeight="100px">
301	                      <PanelMainBody className="pf-v6-u-text-break-word monitoring__pre-line">
302	                        {errorMessage}
303	                      </PanelMainBody>
304	                    </PanelMain>
305	                  </Panel>
306	                </PFAlert>
307	              )}
308	            </FlexItem>
309	            <Flex>
310	              <FlexItem>{isInProgress && <LoadingInline />}</FlexItem>
311	              <FlexItem align={{ default: 'alignRight' }}>
312	                <Button variant="secondary" onClick={setClosed}>
313	                  {t('Cancel')}
314	                </Button>
315	              </FlexItem>
316	              <FlexItem>
317	                <Button variant="primary" onClick={expireSilence}>
318	                  {t('Expire silence')}
319	                </Button>
320	              </FlexItem>
321	            </Flex>
322	          </Flex>
323	        </Flex>
324	      </ModalBody>
325	    </Modal>
326	  );
327	};
328	
329	type SilenceDropdownProps = RouteComponentProps & {
330	  silence: Silence;
331	  toggleText?: string;
332	};
